STRIPE_WEBHOOK_SECRET = os.getenv("STRIPE_WEBHOOK_SECRET")
FRONTEND_URL = os.getenv("FRONTEND_URL")

app = FastAPI()

# Enable CORS for local development
app.add_middleware(
    CORSMiddleware,
    allow_origins=["http://localhost:3000"],
    allow_credentials=True,
    allow_methods=["*"],
    allow_headers=["*"],
)


# ============================================================================
# MODELS
# ============================================================================

class CreateOneTimePaymentRequest(BaseModel):
    amount: int  # cents (e.g., 2000 = $20.00)
    currency: str = "usd"
    product_name: str


class CreateSubscriptionRequest(BaseModel):
    price_id: str  # e.g., "price_1234..."
    customer_email: str


class ClientSecretResponse(BaseModel):
    client_secret: str


# ============================================================================
# ONE-TIME PAYMENT ENDPOINT (Payment Intents API) [4][8]
# ============================================================================

@app.post("/api/create-payment-intent", response_model=ClientSecretResponse)
async def create_payment_intent(request: CreateOneTimePaymentRequest):
    """
    Create a PaymentIntent for one-time payment.
    Returns client_secret for frontend to confirm payment.
    """
    try:
        intent = stripe.PaymentIntent.create(
            amount=request.amount,
            currency=request.currency,
            automatic_payment_methods={"enabled": True},
            description=request.product_name,
        )
        return ClientSecretResponse(client_secret=intent.client_secret)
    except stripe.error.StripeError as e:
        raise HTTPException(status_code=400, detail=str(e))


# ============================================================================
# SUBSCRIPTION CHECKOUT ENDPOINT (Checkout Sessions API) [1][6]
# ============================================================================

@app.post("/api/create-checkout-session", response_model={"client_secret": str})
async def create_checkout_session(request: CreateSubscriptionRequest):
    """
    Create a Checkout Session for subscription.
    Uses Checkout Sessions API (ui_mode: "elements") with Payment Element. [1][6]
    """
    try:
        session = stripe.checkout.Session.create(
            mode="subscription",
            customer_email=request.customer_email,
            line_items=[
                {
                    "price": request.price_id,
                    "quantity": 1,
                }
            ],
            ui_mode="elements",  # Custom Payment Element (not hosted) [1]
            return_url=f"{FRONTEND_URL}/subscription-success?session_id={{CHECKOUT_SESSION_ID}}",
        )
        return {"client_secret": session.client_secret}
    except stripe.error.StripeError as e:
        raise HTTPException(status_code=400, detail=str(e))


# ============================================================================
# WEBHOOK HANDLER [1][6]
# ============================================================================

@app.post("/webhook")
async def webhook_handler(request: Request):
    """
    Handle Stripe webhook events: payment_intent.succeeded, invoice.paid [6]
    """
    payload = await request.body()
    sig_header = request.headers.get("stripe-signature")

    try:
        event = stripe.Webhook.construct_event(
            payload, sig_header, STRIPE_WEBHOOK_SECRET
        )
    except ValueError:
        raise HTTPException(status_code=400, detail="Invalid payload")
    except stripe.error.SignatureVerificationError:
        raise HTTPException(status_code=400, detail="Invalid signature")

