STRIPE_PUBLISHABLE_KEY=pk_test_...
STRIPE_SECRET_KEY=sk_test_...
STRIPE_WEBHOOK_SECRET=whsec_...

# App Configuration
FRONTEND_URL=http://localhost:3000
SUBSCRIPTION_PRICE_ID=price_...
```

*Security Best Practice:* Never expose your `STRIPE_SECRET_KEY` or `STRIPE_WEBHOOK_SECRET` in your frontend code or version control.

---

### 3. Backend Implementation (FastAPI)

Create `main.py`. This includes both checkout flows and the webhook handler.

```python
import os
import stripe
from fastapi import FastAPI, Request, HTTPException
from fastapi.middleware.cors import CORSMiddleware
from pydantic import BaseModel
from dotenv import load_dotenv

load_dotenv()

stripe.api_key = os.getenv("STRIPE_SECRET_KEY")
app = FastAPI()

app.add_middleware(
    CORSMiddleware,
    allow_origins=[os.getenv("FRONTEND_URL", "http://localhost:3000")],
    allow_methods=["*"],
    allow_headers=["*"],
)

class CheckoutRequest(BaseModel):
    purchase_type: str  # 'one-time' or 'subscription'
    email: str

@app.post("/create-payment-intent")
async def create_payment_intent(req: CheckoutRequest):
    try:
        if req.purchase_type == 'one-time':
            # Flow 1: One-time purchase
            intent = stripe.PaymentIntent.create(
                amount=5000, # $50.00 in cents
                currency='usd',
                automatic_payment_methods={"enabled": True},
                receipt_email=req.email
            )
            return {"clientSecret": intent.client_secret}

        elif req.purchase_type == 'subscription':
            # Flow 2: Subscription
            customer = stripe.Customer.create(email=req.email)

            subscription = stripe.Subscription.create(
                customer=customer.id,
                items=[{"price": os.getenv("SUBSCRIPTION_PRICE_ID")}],
                payment_behavior='default_incomplete',
                payment_settings={'save_default_payment_method': 'on_subscription'},
                expand=['latest_invoice.payment_intent']
            )
            return {"clientSecret": subscription.latest_invoice.payment_intent.client_secret}

    except stripe.StripeError as e:
        raise HTTPException(status_code=400, detail=str(e))

@app.post("/webhook")
async def stripe_webhook(request: Request):
    # Webhooks MUST use the raw request body
    payload = await request.body()
    sig_header = request.headers.get("stripe-signature")

    try:
        event = stripe.Webhook.construct_event(
            payload, sig_header, os.getenv("STRIPE_WEBHOOK_SECRET")
        )
    except ValueError:
        raise HTTPException(status_code=400, detail="Invalid payload")
    except stripe.SignatureVerificationError:
        raise HTTPException(status_code=400, detail="Invalid signature")

    # Handle the requested event types
    if event.type == 'payment_intent.succeeded':
        payment_intent = event.data.object
        print(f"✅ Payment Intent Succeeded: {payment_intent.id}")
        # Provision digital product here

    elif event.type == 'invoice.paid':
        invoice = event.data.object
        print(f"✅ Invoice Paid: {invoice.id} for subscription {invoice.subscription}")
        # Provision/renew subscription here

    return {"status": "success"}
```

---

### 4. Frontend Implementation (React)

Create a checkout component that handles the universal Payment Element.

**`Checkout.js`**
```jsx
import React, { useState, useEffect } from "react";
import { loadStripe } from "@stripe/stripe-js";
import { Elements, PaymentElement, useStripe, useElements } from "@stripe/react-stripe-js";

// Ensure you use the exact env variable based on your bundler (e.g. REACT_APP_ / VITE_)
const stripePromise = loadStripe(process.env.REACT_APP_STRIPE_PUBLISHABLE_KEY);

const CheckoutForm = () => {
  const stripe = useStripe();
  const elements = useElements();
  const [error, setError] = useState(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!stripe || !elements) return;

    setIsProcessing(true);
    const { error } = await stripe.confirmPayment({
      elements,
      confirmParams: {
        return_url: `${window.location.origin}/success`,
      },
    });

    if (error) setError(error.message);
    setIsProcessing(false);
  };

  return (
    <form onSubmit={handleSubmit}>
      <PaymentElement />
      <button disabled={isProcessing || !stripe} style={{ marginTop: '20px' }}>
        {isProcessing ? "Processing..." : "Pay Now"}
      </button>
      {error && <div style={{ color: "red", marginTop: '10px' }}>{error}</div>}
    </form>
  );
};

export default function CheckoutPage() {
  const [clientSecret, setClientSecret] = useState("");

  useEffect(() => {
    // Switch between 'one-time' and 'subscription' as needed
    fetch("http://localhost:8000/create-payment-intent", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ purchase_type: "subscription", email: "user@example.com" }),
    })
      .then((res) => res.json())
      .then((data) => setClientSecret(data.clientSecret));
  }, []);

  return (
    <div style={{ maxWidth: "400px", margin: "0 auto" }}>
      <h2>Checkout</h2>
      {clientSecret && (
        <Elements options={{ clientSecret }} stripe={stripePromise}>
          <CheckoutForm />
        </Elements>
      )}
    </div>
  );
}
```

